<?php
 namespace WPAICG\Chat\Frontend; use WPAICG\Chat\Frontend\Shortcode\Validator; use WPAICG\Chat\Frontend\Shortcode\DataProvider; use WPAICG\Chat\Frontend\Shortcode\FeatureManager; use WPAICG\Chat\Frontend\Shortcode\Configurator; use WPAICG\Chat\Frontend\Shortcode\Renderer; use WPAICG\Chat\Frontend\Shortcode\SiteWideHandler; use WPAICG\Chat\Frontend\Assets\AssetsEnqueuer; use WP_Error; if (!defined('ABSPATH')) { exit; } class Shortcode { public static $rendered_bot_ids = []; private $renderer; private $site_wide_handler; public function __construct() { $this->renderer = new Renderer(); $this->site_wide_handler = new SiteWideHandler($this); $this->register_hooks(); } private function register_hooks() { add_action('wp_footer', [$this->site_wide_handler, 'inject_site_wide_chatbot'], 10); } public function render_chatbot_shortcode($atts) { $validation_result = Validator::validate_atts($atts, self::$rendered_bot_ids); if (is_wp_error($validation_result)) { return $this->handle_render_error($validation_result); } $bot_id = $validation_result; $bot_data = DataProvider::get_bot_data($bot_id); if (is_wp_error($bot_data)) { return $this->handle_render_error($bot_data, $bot_id); } $bot_post = $bot_data['post']; $bot_settings = $bot_data['settings']; $feature_flags = FeatureManager::determine_flags($bot_settings); $frontend_config = Configurator::prepare_config($bot_id, $bot_post, $bot_settings, $feature_flags); Assets::require_assets( $feature_flags['pdf_ui_enabled'], $feature_flags['enable_copy_button'], $feature_flags['starters_ui_enabled'], $feature_flags['sidebar_ui_enabled'], $feature_flags['feedback_ui_enabled'], $feature_flags['tts_ui_enabled'], $feature_flags['enable_voice_input_ui'], true, $feature_flags['image_upload_ui_enabled'], $feature_flags['file_upload_ui_enabled'], $feature_flags['enable_realtime_voice_ui'] ); if (class_exists(AssetsEnqueuer::class)) { (new AssetsEnqueuer())->process_assets(); } self::$rendered_bot_ids[$bot_id] = true; return $this->renderer->render_chatbot_html($bot_id, $bot_settings, $feature_flags, $frontend_config); } private function handle_render_error(WP_Error $error, $bot_id = null) { if (\WPAICG\AIPKit_Role_Manager::user_can_view_admin_notices()) { $message = $error->get_error_message(); $code = $error->get_error_code(); if ($code === 'already_rendered') { return '<p style="color: orange; font-style: italic; margin: 1em 0;">' . esc_html($message) . '</p>'; } else { return '<p style="color: red; font-style: italic; margin: 1em 0;">' . esc_html($message) . '</p>'; } } if ($bot_id && $error->get_error_code() === 'already_rendered') { self::$rendered_bot_ids[$bot_id] = true; } return ''; } } 